import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Check, AlertTriangle, Sparkles, ArrowRight } from 'lucide-react';
import { Schedule, ClassGroup, TimeSlot, Teacher, DesignSettings } from '../types';
import { detectConflicts } from '../utils';
import TimetableGrid from './TimetableGrid';

interface Proposal {
    id: string;
    schedule: Schedule;
    conflictCount: number;
}

interface Props {
    isOpen: boolean;
    onClose: () => void;
    onApply: (schedule: Schedule) => void;
    proposals: Proposal[];
    classes: ClassGroup[];
    slots: TimeSlot[];
    teachers: Teacher[];
    design: DesignSettings;
}

const OptimizationModal: React.FC<Props> = ({
    isOpen, onClose, onApply, proposals, classes, slots, teachers, design
}) => {
    const [selectedId, setSelectedId] = useState<string | null>(null);

    useEffect(() => {
        if (isOpen && proposals.length > 0) {
            setSelectedId(proposals[0].id);
        }
    }, [isOpen, proposals]);

    const selectedProposal = proposals.find(p => p.id === selectedId);

    // Calculate conflicts live for the preview
    const previewConflicts = selectedProposal 
        ? detectConflicts(selectedProposal.schedule, teachers, classes, slots) 
        : {};

    const handleApply = () => {
        if (selectedProposal) {
            onApply(selectedProposal.schedule);
            onClose();
        }
    };

    return (
        <AnimatePresence>
            {isOpen && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 lg:p-8">
                    <motion.div 
                        initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                        className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm"
                        onClick={onClose}
                    />
                    <motion.div 
                        initial={{ scale: 0.95, opacity: 0, y: 20 }} 
                        animate={{ scale: 1, opacity: 1, y: 0 }} 
                        exit={{ scale: 0.95, opacity: 0, y: 20 }}
                        className="relative bg-white dark:bg-slate-900 rounded-2xl shadow-2xl w-full max-w-7xl h-[85vh] flex flex-col overflow-hidden border border-slate-200 dark:border-slate-800 transition-colors"
                    >
                        {/* Header */}
                        <div className="flex justify-between items-center px-6 py-4 border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 z-10 transition-colors">
                            <div className="flex items-center gap-3">
                                <div className="bg-indigo-100 dark:bg-indigo-900/30 p-2 rounded-lg text-indigo-600 dark:text-indigo-400">
                                    <Sparkles size={24} />
                                </div>
                                <div>
                                    <h2 className="text-xl font-bold text-slate-800 dark:text-white">د هوښیار سمون وړاندیزونه</h2>
                                    <p className="text-sm text-slate-500 dark:text-slate-400">یو غوره وړاندیز وټاکئ او پلی یې کړئ</p>
                                </div>
                            </div>
                            <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 transition-colors">
                                <X size={24} />
                            </button>
                        </div>

                        <div className="flex flex-1 overflow-hidden">

                            {/* Sidebar List */}
                            <div className="w-80 bg-slate-50 dark:bg-slate-950 border-l border-slate-200 dark:border-slate-800 flex flex-col overflow-y-auto p-4 gap-3 transition-colors">
                                {proposals.map((p, index) => (
                                    <button
                                        key={p.id}
                                        onClick={() => setSelectedId(p.id)}
                                        className={`text-right p-4 rounded-xl border transition-all relative overflow-hidden group ${
                                            selectedId === p.id 
                                            ? 'bg-white dark:bg-slate-800 border-indigo-500 dark:border-indigo-400 shadow-md ring-1 ring-indigo-500 dark:ring-indigo-400' 
                                            : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 hover:border-indigo-300 dark:hover:border-indigo-700 hover:shadow-sm'
                                        }`}
                                    >
                                        <div className="flex justify-between items-center mb-2">
                                            <span className={`font-bold ${selectedId === p.id ? 'text-indigo-700 dark:text-indigo-300' : 'text-slate-700 dark:text-slate-200'}`}>
                                                {index + 1} اختیار
                                            </span>
                                            {p.conflictCount === 0 && (
                                                <span className="bg-emerald-100 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-400 text-[10px] px-2 py-0.5 rounded-full font-bold">غوره</span>
                                            )}
                                        </div>

                                        <div className={`flex items-center gap-2 text-sm ${p.conflictCount === 0 ? 'text-emerald-600 dark:text-emerald-400' : 'text-amber-600 dark:text-amber-400'}`}>
                                            {p.conflictCount === 0 ? <Check size={16} /> : <AlertTriangle size={16} />}
                                            <span>{p.conflictCount} تضاد موندل شوی</span>
                                        </div>

                                        {selectedId === p.id && (
                                            <div className="absolute inset-y-0 right-0 w-1.5 bg-indigo-500 dark:bg-indigo-400" />
                                        )}
                                    </button>
                                ))}
                            </div>

                            {/* Preview Area */}
                            <div className="flex-1 bg-slate-100 dark:bg-slate-950 p-4 overflow-hidden relative flex flex-col transition-colors">
                                <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-slate-200 dark:border-slate-800 flex-1 overflow-hidden relative transition-colors">
                                     <div className="absolute inset-0 overflow-auto p-4">
                                         {selectedProposal && (
                                             <TimetableGrid 
                                                 classes={classes}
                                                 slots={slots}
                                                 teachers={teachers}
                                                 design={design}
                                                 schedule={selectedProposal.schedule}
                                                 conflicts={previewConflicts}
                                                 // Pass empty/noop to disable editing in preview
                                                 readOnly={true}
                                             />
                                         )}
                                     </div>
                                </div>
                            </div>
                        </div>

                        {/* Footer Actions */}
                        <div className="px-6 py-4 border-t border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 flex justify-between items-center transition-colors">
                            <div className="text-sm text-slate-500 dark:text-slate-400">
                                {proposals.length} وړاندیزونه موندل شول
                            </div>
                            <div className="flex gap-3">
                                <button 
                                    onClick={onClose}
                                    className="px-5 py-2.5 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl font-medium transition-colors"
                                >
                                    لغوه
                                </button>
                                <button 
                                    onClick={handleApply}
                                    disabled={!selectedProposal}
                                    className="px-6 py-2.5 bg-indigo-600 dark:bg-indigo-500 hover:bg-indigo-700 dark:hover:bg-indigo-600 text-white rounded-xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none flex items-center gap-2 transition-transform active:scale-95 disabled:opacity-50"
                                >
                                    <span>پلی کول</span>
                                    <ArrowRight size={18} className="rotate-180" />
                                </button>
                            </div>
                        </div>

                    </motion.div>
                </div>
            )}
        </AnimatePresence>
    );
};

export default OptimizationModal;

import React, { useContext, useState } from 'react';
import { AppContext } from '../App';
import { Save } from 'lucide-react';
import { CellDesign } from '../types';

const DesignPage: React.FC = () => {
  const { state, dispatch, addToast } = useContext(AppContext);
  const isDarkMode = state.ui.theme === 'dark' || (state.ui.theme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches);

  // Deep copy to avoid reference issues during edit
  const [design, setDesign] = useState(JSON.parse(JSON.stringify(state.design)));

  const updateField = (type: 'lesson' | 'break', field: keyof CellDesign, value: any) => {
    setDesign((prev: any) => ({
        ...prev,
        [type]: { ...prev[type], [field]: value }
    }));
  };

  const handleSave = () => {
    dispatch({ type: 'UPDATE_DESIGN', payload: design });
    addToast('success', 'د مهال ویش ظاهري بڼه بدله شوه');
  };

  const renderControls = (type: 'lesson' | 'break', label: string) => {
    // Adaptive background for preview if using default white
    let previewBg = design[type].backgroundColor;
    if (isDarkMode && (previewBg === '#ffffff' || previewBg === 'white' || previewBg.toLowerCase() === '#fff')) {
        previewBg = type === 'break' ? '#1e293b' : '#0f172a';
    }

    return (
        <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 transition-colors">
            <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-4 pb-2 border-b border-slate-100 dark:border-slate-700">{label}</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

                <div>
                    <label className="text-xs font-bold text-slate-500 dark:text-slate-400 block mb-1">د شالید (Background) رنګ</label>
                    <div className="flex gap-2">
                        <input type="color" className="w-10 h-10 rounded cursor-pointer dark:bg-slate-900 border-none" value={design[type].backgroundColor} onChange={(e) => updateField(type, 'backgroundColor', e.target.value)} />
                        <input type="text" className="flex-1 border dark:border-slate-600 rounded px-2 text-sm bg-white dark:bg-slate-900 dark:text-white" value={design[type].backgroundColor} onChange={(e) => updateField(type, 'backgroundColor', e.target.value)} />
                    </div>
                </div>

                <div>
                    <label className="text-xs font-bold text-slate-500 dark:text-slate-400 block mb-1">د څنډې (Border) رنګ</label>
                    <div className="flex gap-2">
                        <input type="color" className="w-10 h-10 rounded cursor-pointer dark:bg-slate-900 border-none" value={design[type].borderColor} onChange={(e) => updateField(type, 'borderColor', e.target.value)} />
                        <input type="text" className="flex-1 border dark:border-slate-600 rounded px-2 text-sm bg-white dark:bg-slate-900 dark:text-white" value={design[type].borderColor} onChange={(e) => updateField(type, 'borderColor', e.target.value)} />
                    </div>
                </div>

                <div>
                    <label className="text-xs font-bold text-slate-500 dark:text-slate-400 block mb-1">د څنډې پنډوالی ({design[type].borderWidth}px)</label>
                    <input type="range" min="0" max="5" className="w-full accent-primary-500" value={design[type].borderWidth} onChange={(e) => updateField(type, 'borderWidth', parseInt(e.target.value))} />
                </div>

                <div>
                    <label className="text-xs font-bold text-slate-500 dark:text-slate-400 block mb-1">د کونجونو ګردوالی ({design[type].borderRadius}px)</label>
                    <input type="range" min="0" max="20" className="w-full accent-primary-500" value={design[type].borderRadius} onChange={(e) => updateField(type, 'borderRadius', parseInt(e.target.value))} />
                </div>

                <div>
                    <label className="text-xs font-bold text-slate-500 dark:text-slate-400 block mb-1">داخلي واټن/Margin ({design[type].margin}px)</label>
                    <input type="range" min="0" max="10" className="w-full accent-primary-500" value={design[type].margin} onChange={(e) => updateField(type, 'margin', parseInt(e.target.value))} />
                </div>

                {type === 'lesson' && (
                    <div>
                        <label className="text-xs font-bold text-slate-500 dark:text-slate-400 block mb-1">د فونټ اندازه ({design[type].fontSize}px)</label>
                        <input type="range" min="10" max="20" className="w-full accent-primary-500" value={design[type].fontSize} onChange={(e) => updateField(type, 'fontSize', parseInt(e.target.value))} />
                    </div>
                )}

            </div>

            {/* Preview */}
            <div className="mt-6 p-4 bg-slate-100 dark:bg-slate-900/50 rounded-lg flex justify-center transition-colors">
                <div style={{
                    width: '140px', height: '80px',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    backgroundColor: previewBg,
                    borderColor: design[type].borderColor,
                    borderWidth: `${design[type].borderWidth}px`,
                    borderStyle: design[type].borderStyle,
                    borderRadius: `${design[type].borderRadius}px`,
                    margin: 0, // Margin handled by container in preview
                    fontSize: `${design[type].fontSize}px`,
                    boxShadow: design[type].shadow === 'none' ? 'none' : 'inset 0 2px 4px 0 rgb(0 0 0 / 0.05)',
                    color: isDarkMode && (previewBg === '#1e293b' || previewBg === '#0f172a') ? '#f1f5f9' : '#000'
                }}>
                    <span>بیلګه متن</span>
                </div>
            </div>
        </div>
    );
  };

  return (
    <div className="max-w-4xl mx-auto pb-20">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-slate-800 dark:text-white">د مهال ویش ډیزاین</h2>
        <button 
            onClick={handleSave}
            className="bg-primary-600 hover:bg-primary-700 text-white px-6 py-2 rounded-xl flex items-center gap-2 shadow-lg transition-colors"
        >
            <Save size={20} />
            <span>بدلونونه ثبت کړئ</span>
        </button>
      </div>

      <div className="grid gap-6">
        {renderControls('lesson', 'د درس خونو سټایل')}
        {renderControls('break', 'د تفریح سټایل')}
      </div>
    </div>
  );
};

export default DesignPage;

import React, { useContext, useState } from 'react';
import { AppContext } from '../App';
import { ArrowRight, Download, Layout, Type, Palette, Printer, Stamp, Eye, Grid, AlignVerticalSpaceAround, MoveVertical, ChevronLeft, ChevronRight, Settings2, Maximize2, Minimize2, X } from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import TimetableTemplate from './TimetableTemplate';

interface Props {
  onBack: () => void;
}

type TabType = 'layout' | 'content' | 'style' | 'extras';

const PrintPreviewPage: React.FC<Props> = ({ onBack }) => {
  const { state, dispatch, addToast } = useContext(AppContext);
  const { printDesign } = state;
  const [activeTab, setActiveTab] = useState<TabType>('layout');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isFullScreen, setIsFullScreen] = useState(false);

  const updateDesign = (key: keyof typeof printDesign, value: any) => {
    dispatch({ type: 'UPDATE_PRINT_DESIGN', payload: { [key]: value } });
  };

  const handleDownload = async () => {
    const element = document.getElementById('export-canvas-container');
    if (!element) return;

    addToast('info', 'د لوړ کیفیت فایل جوړولو په حال کې...');

    try {
        // Wait a moment for fonts to potentially settle if changed
        await new Promise(r => setTimeout(r, 500));

        const canvas = await html2canvas(element, {
            scale: 3, // Higher scale for crisp text
            useCORS: true,
            logging: false,
            backgroundColor: '#ffffff',
        });

        const imgData = canvas.toDataURL('image/jpeg', 0.95);
        const pdf = new jsPDF({
            orientation: 'landscape',
            unit: 'mm',
            format: 'a4'
        });

        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();
        const imgProps = pdf.getImageProperties(imgData);
        const ratio = imgProps.width / imgProps.height;

        let renderWidth = pdfWidth;
        let renderHeight = pdfWidth / ratio;

        // Fit within the page logic
        if (renderHeight > pdfHeight) {
             renderHeight = pdfHeight;
             renderWidth = pdfHeight * ratio;
        }

        // Center the image
        const x = (pdfWidth - renderWidth) / 2;
        const y = (pdfHeight - renderHeight) / 2;

        pdf.addImage(imgData, 'JPEG', x, y, renderWidth, renderHeight);

        const date = new Date();
        const dateStr = date.getFullYear() + 
                        String(date.getMonth() + 1).padStart(2, '0') + 
                        String(date.getDate()).padStart(2, '0');

        pdf.save(`timetable_pro_${dateStr}.pdf`);
        addToast('success', 'PDF فایل ډاونلوډ شو');

    } catch (e) {
        console.error(e);
        addToast('error', 'د فایل په جوړولو کې ستونزه');
    }
  };

  const TabButton = ({ id, label, icon }: { id: TabType, label: string, icon: React.ReactNode }) => (
    <button 
        onClick={() => setActiveTab(id)}
        className={`flex-1 py-3 flex flex-col items-center justify-center gap-1 text-xs font-medium transition-all border-b-2 ${
            activeTab === id 
            ? 'border-indigo-600 text-indigo-700 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30' 
            : 'border-transparent text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800'
        }`}
    >
        {icon}
        <span>{label}</span>
    </button>
  );

  return (
    <div className="h-full flex flex-col bg-slate-100 dark:bg-slate-950 transition-colors duration-300">
      {/* Top Bar - Hidden in Full Screen */}
      {!isFullScreen && (
          <div className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-4 md:px-6 py-3 flex justify-between items-center shadow-sm z-20 flex-shrink-0 transition-colors">
            <div className="flex items-center gap-4">
                <button onClick={onBack} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors text-slate-600 dark:text-slate-400" title="بېرته مدیریت ته">
                    <ArrowRight size={24} />
                </button>
                <div className="flex items-center gap-3">
                    <h2 className="text-lg font-bold text-slate-800 dark:text-white hidden md:block">د چاپ او PDF سټوډیو</h2>
                    <span className="bg-indigo-100 dark:bg-indigo-900 text-indigo-700 dark:text-indigo-400 text-[10px] px-2 py-0.5 rounded-full font-bold">PRO</span>

                    {!isSidebarOpen && (
                        <button 
                            onClick={() => setIsSidebarOpen(true)}
                            className="flex items-center gap-2 text-sm text-indigo-600 dark:text-indigo-400 hover:bg-indigo-50 dark:hover:bg-indigo-900/40 px-3 py-1.5 rounded-lg border border-indigo-100 dark:border-indigo-900 transition-colors"
                        >
                            <Settings2 size={16} />
                            <span>ترتیبات</span>
                        </button>
                    )}
                </div>
            </div>
            <div className="flex gap-3">
                <button 
                    onClick={() => setIsFullScreen(true)}
                    className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg text-slate-600 dark:text-slate-400 transition-colors"
                    title="پوره سکرین"
                >
                    <Maximize2 size={20} />
                </button>
                <button 
                    onClick={() => window.print()}
                    className="px-3 md:px-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700 rounded-lg flex items-center gap-2 font-medium transition-colors text-sm"
                >
                    <Printer size={18} />
                    <span className="hidden md:inline">سمدستي چاپ</span>
                </button>
                <button 
                    onClick={handleDownload}
                    className="px-4 md:px-5 py-2 bg-indigo-600 dark:bg-indigo-500 text-white hover:bg-indigo-700 dark:hover:bg-indigo-600 rounded-lg flex items-center gap-2 shadow-lg shadow-indigo-200 dark:shadow-none font-bold transition-colors text-sm"
                >
                    <Download size={18} />
                    <span className="hidden md:inline">د وروستۍ نسخې ډاونلوډ</span>
                    <span className="md:hidden">ډاونلوډ</span>
                </button>
            </div>
          </div>
      )}

      <div className="flex-1 overflow-hidden flex relative">

        {/* Left Control Panel (Collapsible) - Hidden in Full Screen */}
        {!isFullScreen && (
            <div 
                className={`bg-white dark:bg-slate-900 border-l border-slate-200 dark:border-slate-800 flex flex-col shadow-xl z-10 transition-all duration-300 ease-in-out absolute inset-y-0 right-0 md:static ${
                    isSidebarOpen ? 'w-80 translate-x-0' : 'w-0 translate-x-full opacity-0 md:opacity-100 md:w-0 md:translate-x-0 overflow-hidden'
                }`}
            >
                {/* Collapse Button */}
                <button 
                    onClick={() => setIsSidebarOpen(false)}
                    className="absolute top-1/2 -left-3 z-50 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 shadow-md rounded-full p-1 text-slate-500 hover:text-indigo-600 hidden md:block"
                    title="د ترتیباتو پینل وتړئ"
                >
                    <ChevronRight size={16} />
                </button>

                {/* Tabs */}
                <div className="flex border-b border-slate-200 dark:border-slate-800">
                    <TabButton id="layout" label="جوړښت" icon={<Layout size={18} />} />
                    <TabButton id="content" label="محتوا" icon={<Type size={18} />} />
                    <TabButton id="style" label="سټایل" icon={<Palette size={18} />} />
                    <TabButton id="extras" label="نور" icon={<Stamp size={18} />} />
                </div>

                {/* Controls Scroll Area */}
                <div className="flex-1 overflow-y-auto p-6 space-y-6 pb-20 scrollbar-hide">

                    {/* LAYOUT TAB */}
                    {activeTab === 'layout' && (
                        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
                            <div>
                                <label className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-3 block">د حجرو ابعاد (مهم)</label>
                                <div className="space-y-4 bg-amber-50 dark:bg-amber-900/20 border border-amber-100 dark:border-amber-900/30 p-3 rounded-lg">
                                    <div>
                                        <div className="flex justify-between text-sm mb-1 text-slate-700 dark:text-slate-300">
                                            <span>د قطار لږترلږه لوړوالی</span>
                                            <span className="font-mono text-slate-500 dark:text-slate-400">{printDesign.cellMinHeight || 90}px</span>
                                        </div>
                                        <input 
                                            type="range" min="30" max="300" step="5"
                                            value={printDesign.cellMinHeight || 90}
                                            onChange={(e) => updateDesign('cellMinHeight', parseInt(e.target.value))}
                                            className="w-full accent-amber-600"
                                        />
                                        <p className="text-[10px] text-amber-700 dark:text-amber-400 mt-1 leading-tight">که متنونه نه ځاییږي، دا اندازه لوړه کړئ.</p>
                                    </div>
                                    <div>
                                        <div className="flex justify-between text-sm mb-1 text-slate-700 dark:text-slate-300">
                                            <span>داخلي واټن (Padding)</span>
                                            <span className="font-mono text-slate-500 dark:text-slate-400">{printDesign.cellPadding || 4}px</span>
                                        </div>
                                        <input 
                                            type="range" min="0" max="50" step="1"
                                            value={printDesign.cellPadding || 4}
                                            onChange={(e) => updateDesign('cellPadding', parseInt(e.target.value))}
                                            className="w-full accent-amber-600"
                                        />
                                    </div>
                                    <div>
                                        <div className="flex justify-between text-sm mb-1 text-slate-700 dark:text-slate-300">
                                            <span>د لوست او ښوونکي ترمنځ واټن</span>
                                            <span className="font-mono text-slate-500 dark:text-slate-400">{printDesign.cellGap || 6}px</span>
                                        </div>
                                        <input 
                                            type="range" min="0" max="50" step="1"
                                            value={printDesign.cellGap || 6}
                                            onChange={(e) => updateDesign('cellGap', parseInt(e.target.value))}
                                            className="w-full accent-amber-600"
                                        />
