  const [isFullScreen, setIsFullScreen] = useState(false);

  const [showOptModal, setShowOptModal] = useState(false);
  const [optProposals, setOptProposals] = useState<{id: string, schedule: Schedule, conflictCount: number}[]>([]);

  const handleOptimizeStart = async () => {
    setIsOptimizing(true);
    setTimeout(() => {
        try {
            const proposals = generateOptimizationProposals(schedule, classes, timeSlots);
            if (proposals.length === 0) {
                addToast('info', 'اوسنی مهال ویش لا دمخه غوره دی');
            } else {
                setOptProposals(proposals);
                setShowOptModal(true);
            }
        } catch (e) {
            console.error(e);
            addToast('error', 'تېروتنه وشوه');
        } finally {
            setIsOptimizing(false);
        }
    }, 100);
  };

  const handleApplyOptimization = (newSchedule: Schedule) => {
      dispatch({ type: 'RECORD' }); 
      dispatch({ type: 'REPLACE_SCHEDULE', payload: newSchedule });
      addToast('success', t('toast_optimized'));
      setShowOptModal(false);
  };

  return (
    <div className="flex flex-col h-full gap-6 animate-in fade-in duration-500">
      {!isFullScreen && (
        <div className="flex flex-col md:flex-row gap-4 justify-between items-start md:items-center bg-white dark:bg-slate-800 p-4 rounded-3xl shadow-sm border border-slate-200 dark:border-slate-700 transition-colors">
            <div className="flex flex-wrap gap-4">
            <StatBadge icon={<Users size={18} />} label={t('dashboard_stats_teachers')} value={teachers.length} color="bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300" />
            <StatBadge icon={<GraduationCap size={18} />} label={t('dashboard_stats_classes')} value={classes.length} color="bg-emerald-100 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300" />
            <StatBadge 
                icon={<AlertTriangle size={18} />} 
                label={t('dashboard_stats_conflicts')} 
                value={conflictCount} 
                color={conflictCount > 0 ? "bg-red-100 dark:bg-red-900/40 text-red-700 dark:text-red-300" : "bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-slate-400"} 
            />
            </div>

            <div className="flex gap-2 w-full md:w-auto">
            <div className="flex gap-1 bg-slate-100 dark:bg-slate-700 p-1 rounded-xl">
                <button onClick={() => dispatch({ type: 'UNDO' })} disabled={!canUndo} className="p-2 hover:bg-white dark:hover:bg-slate-600 rounded-lg disabled:opacity-30 transition-all" title={t('dashboard_undo')}>
                    <Undo size={20} />
                </button>
                <button onClick={() => dispatch({ type: 'REDO' })} disabled={!canRedo} className="p-2 hover:bg-white dark:hover:bg-slate-600 rounded-lg disabled:opacity-30 transition-all" title={t('dashboard_redo')}>
                    <Redo size={20} />
                </button>
            </div>

            <button onClick={() => setIsFullScreen(true)} className="p-2 bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 text-slate-600 dark:text-slate-300 rounded-xl transition-colors" title={t('dashboard_fullscreen')}>
                <Maximize2 size={20} />
            </button>

            <button
                onClick={handleOptimizeStart}
                disabled={isOptimizing}
                className="flex-1 md:flex-none flex items-center gap-2 bg-gradient-to-r from-primary-600 to-primary-500 hover:scale-105 text-white px-6 py-2 rounded-xl shadow-lg transition-all disabled:opacity-70 font-bold"
            >
                <Wand2 size={18} className={isOptimizing ? "animate-spin" : ""} />
                <span>{isOptimizing ? t('dashboard_optimizing') : t('dashboard_optimize_btn')}</span>
            </button>
            </div>
        </div>
      )}

      <div className={`
        ${isFullScreen 
            ? 'fixed inset-0 z-50 bg-slate-100 dark:bg-slate-950 p-8 flex flex-col items-center justify-center' 
            : 'flex-1 bg-white dark:bg-slate-800 rounded-3xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden relative'
        }
      `}>
         {isFullScreen && (
            <div className="absolute top-4 right-4 z-50 flex gap-2">
                 <button onClick={() => setIsFullScreen(false)} className="p-2 bg-red-100 dark:bg-red-900 text-red-600 dark:text-red-400 hover:bg-red-200 dark:hover:bg-red-800 rounded-full transition-colors shadow-sm">
                    <X size={24} />
                 </button>
            </div>
         )}

         <div className={`w-full h-full overflow-hidden ${isFullScreen ? 'max-w-[95vw] max-h-[90vh] bg-white dark:bg-slate-800 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 flex flex-col' : ''}`}>
             <TimetableGrid classes={classes} slots={timeSlots} schedule={schedule} conflicts={conflicts} teachers={teachers} design={state.design} />
         </div>
      </div>

      <OptimizationModal isOpen={showOptModal} onClose={() => setShowOptModal(false)} onApply={handleApplyOptimization} proposals={optProposals} classes={classes} slots={timeSlots} teachers={teachers} design={state.design} />
    </div>
  );
};

const StatBadge = ({ icon, label, value, color }: any) => (
  <div className={`flex items-center gap-2 px-4 py-2 rounded-full ${color} font-black text-sm transition-colors shadow-sm`}>
    {icon}
    <span>{label}: {value}</span>
  </div>
);

export default Dashboard;

import React, { useContext, useState } from 'react';
import { AppContext } from '../App';
import { ClassGroup, TimeSlot, Schedule, Teacher, DesignSettings, LessonData } from '../types';
import { Plus, Coffee, AlertCircle } from 'lucide-react';
import { getContrastColor } from '../utils';
import EditModal from './EditModal';

interface Props {
  classes: ClassGroup[];
  slots: TimeSlot[];
  schedule: Schedule;
  conflicts: { [key: string]: boolean };
  teachers: Teacher[];
  design: DesignSettings;
  readOnly?: boolean;
}

const TimetableGrid: React.FC<Props> = ({ classes, slots, schedule, conflicts, teachers, design, readOnly = false }) => {
  const { dispatch, state, t } = useContext(AppContext);
  const isDarkMode = state.ui.theme === 'dark' || (state.ui.theme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches);

  const [editingCell, setEditingCell] = useState<{ key: string, data: LessonData | null } | null>(null);
  const [dragSource, setDragSource] = useState<string | null>(null);
  const [dragOverKey, setDragOverKey] = useState<string | null>(null);

  const handleCellClick = (key: string) => {
    if (readOnly) return;
    setEditingCell({ key, data: schedule[key] || null });
  };

  const handleSaveLesson = (data: LessonData) => {
    if (readOnly) return;
    if (editingCell) {
      dispatch({ type: 'SET_LESSON', payload: { key: editingCell.key, data } });
    }
  };

  const handleDeleteLesson = () => {
    if (readOnly) return;
    if (editingCell) {
      dispatch({ type: 'SET_LESSON', payload: { key: editingCell.key, data: null } });
      setEditingCell(null);
    }
  };

  const onDragStart = (e: React.DragEvent, key: string) => {
    if (readOnly || !schedule[key]) {
        e.preventDefault();
        return;
    }
    setDragSource(key);
    e.dataTransfer.effectAllowed = 'move';
  };

  const onDragOver = (e: React.DragEvent, key: string) => {
    e.preventDefault(); 
    if (readOnly) return;
    const sourceClass = dragSource?.split('_')[0];
    const targetClass = key.split('_')[0];
    if (sourceClass === targetClass) {
        setDragOverKey(key);
        e.dataTransfer.dropEffect = 'move';
    } else {
        e.dataTransfer.dropEffect = 'none';
    }
  };

  const onDrop = (e: React.DragEvent, targetKey: string) => {
    e.preventDefault();
    if (readOnly) return;
    if (dragSource && dragSource !== targetKey) {
        const sourceClass = dragSource.split('_')[0];
        const targetClass = targetKey.split('_')[0];
        if (sourceClass === targetClass) {
            dispatch({ type: 'MOVE_LESSON', payload: { fromKey: dragSource, toKey: targetKey } });
        }
    }
    setDragSource(null);
    setDragOverKey(null);
  };

  const getTeacher = (id: string) => teachers.find(t_item => t_item.id === id);

  return (
    <>
      <div className="w-full h-full overflow-auto bg-white dark:bg-slate-900 rounded-2xl transition-colors">
        <div className="inline-block min-w-max">
          {/* Header Row */}
          <div className="flex sticky-header bg-slate-50 dark:bg-slate-800 shadow-sm border-b border-slate-200 dark:border-slate-700 z-20">
            <div className="sticky-col left-0 w-32 p-4 font-black text-slate-700 dark:text-slate-200 bg-slate-50 dark:bg-slate-800 border-l border-slate-200 dark:border-slate-700 text-center flex items-center justify-center shadow-[4px_0_10px_-5px_rgba(0,0,0,0.1)] z-30">
              {t('grid_classes')}
            </div>
            {slots.map((slot) => (
              <div key={slot.id} className="w-40 p-3 text-center border-l border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800">
                <div className="text-sm font-black text-slate-800 dark:text-slate-100">
                    {slot.type === 'lesson' ? `${slot.index + 1} ${t('grid_lesson_unit')}` : t('grid_break')}
                </div>
                <div className="text-[10px] font-bold text-slate-500 dark:text-slate-400 mt-1 bg-slate-200 dark:bg-slate-700 inline-block px-2 py-0.5 rounded-full">
                  {slot.start} - {slot.end}
                </div>
              </div>
            ))}
          </div>

          {/* Rows */}
          {classes.map((cls) => (
            <div key={cls.id} className="flex border-b border-slate-100 dark:border-slate-800 hover:bg-slate-50/50 dark:hover:bg-slate-800/30 transition-colors">
              <div className="sticky-col left-0 w-32 p-3 font-bold text-sm text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-900 border-l border-slate-200 dark:border-slate-800 flex items-center justify-center shadow-[4px_0_10px_-5px_rgba(0,0,0,0.1)] z-10 transition-colors">
                <div className="truncate px-1">{cls.name}</div>
              </div>

              {slots.map((slot) => {
                const key = `${cls.id}_${slot.id}`;
                const lesson = schedule[key];
                const isConflict = conflicts[key];
                const isBreak = slot.type === 'break';
                const isDraggingOver = dragOverKey === key;

                const style = isBreak ? design.break : design.lesson;
                const teacher = lesson ? getTeacher(lesson.teacherId) : null;
                const tColor = teacher ? teacher.color : '#ccc';
                const tContrast = teacher ? getContrastColor(tColor) : '#000';

                let cellBg = style.backgroundColor;
                if (isDarkMode && (cellBg === '#ffffff' || cellBg === 'white' || cellBg.toLowerCase() === '#fff')) {
                    cellBg = isBreak ? '#1e293b' : '#0f172a';
                }

                if (isBreak) {
                  return (
                    <div key={key} className="w-40 p-1 border-l border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/20 flex items-center justify-center opacity-80 transition-colors">
                         <div className="w-full h-full flex flex-col items-center justify-center gap-1 rounded-xl text-slate-400 dark:text-slate-500" style={{ backgroundColor: cellBg }}>
                            <Coffee size={18} />
                         </div>
                    </div>
                  );
                }

                return (
                  <div key={key} className={`w-40 p-1 border-l border-slate-100 dark:border-slate-800 relative group transition-colors ${isDraggingOver ? 'bg-primary-50 dark:bg-primary-900/20' : ''}`} onDragOver={(e) => onDragOver(e, key)} onDrop={(e) => onDrop(e, key)}>
                    <div 
                        onClick={() => handleCellClick(key)} draggable={!!lesson && !readOnly} onDragStart={(e) => onDragStart(e, key)}
                        className={`w-full h-full min-h-[70px] flex flex-col items-center justify-center text-center relative transition-all ${readOnly ? '' : 'cursor-pointer'} ${lesson && !readOnly ? 'hover:scale-[1.03] hover:shadow-lg z-10' : ''} ${isConflict ? 'ring-2 ring-red-500 shadow-lg shadow-red-500/20' : ''}`}
                        style={{
                            backgroundColor: cellBg, 
                            border: lesson ? `${style.borderWidth}px ${style.borderStyle} ${isConflict ? '#ef4444' : style.borderColor}` : '1px dashed #e2e8f0',
                            borderRadius: `${style.borderRadius}px`,
                            boxShadow: lesson ? style.shadow : 'none',
                            fontSize: `${style.fontSize}px`,
                            margin: `${style.margin}px`
                        }}
                    >
                        {lesson ? (
                            <>
                                <div className="font-bold leading-tight mb-1 px-1 truncate w-full text-slate-800 dark:text-slate-100">{lesson.subject}</div>
                                {teacher && (
                                    <div className="text-[0.75em] px-2 py-0.5 rounded-full max-w-[90%] truncate font-black" style={{ backgroundColor: tColor, color: tContrast }}>{teacher.name}</div>
                                )}
                                {isConflict && (
                                    <div className="absolute -top-1.5 -right-1.5 bg-red-500 text-white rounded-full p-1 shadow-lg z-10"><AlertCircle size={12} /></div>
                                )}
                            </>
                        ) : (
                            !readOnly && <Plus className="text-slate-300 dark:text-slate-600 w-5 h-5 opacity-0 group-hover:opacity-100 transition-opacity" />
                        )}
                    </div>
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>
      {!readOnly && (
          <EditModal isOpen={!!editingCell} initialData={editingCell?.data} teachers={teachers} onClose={() => setEditingCell(null)} onSave={handleSaveLesson} onDelete={handleDeleteLesson} />
      )}
    </>
  );
};

export default TimetableGrid;

import React, { useContext, useState } from 'react';
import { AppContext } from '../App';
import { Plus, Trash2, Edit2, Check, X, Palette, Shuffle } from 'lucide-react';
import { generateId } from '../utils';
import { COLORS } from '../types';
import ConfirmModal from './ConfirmModal';

const Teachers: React.FC = () => {
  const { state, dispatch, addToast, t } = useContext(AppContext);
  const [newTeacherName, setNewTeacherName] = useState('');
  const [colorMode, setColorMode] = useState<'random' | 'custom'>('random');
  const [customColor, setCustomColor] = useState('#3b82f6');

  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState('');
  const [deleteId, setDeleteId] = useState<string | null>(null);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTeacherName.trim()) return;
    const color = colorMode === 'random' ? COLORS[Math.floor(Math.random() * COLORS.length)] : customColor;
    dispatch({ type: 'ADD_TEACHER', payload: { id: generateId(), name: newTeacherName, color } });
    setNewTeacherName('');
    addToast('success', t('toast_teacher_added'));
  };

  const startEdit = (t_item: any) => {
    setEditingId(t_item.id);
    setEditName(t_item.name);
  };

  const saveEdit = (t_item: any) => {
    dispatch({ type: 'UPDATE_TEACHER', payload: { ...t_item, name: editName } });
    setEditingId(null);
    addToast('success', 'سم شو');
  };

  const confirmDelete = () => {
    if (deleteId) {
        dispatch({ type: 'DELETE_TEACHER', payload: deleteId });
        addToast('success', 'حذف شو');
        setDeleteId(null);
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-in fade-in duration-500">
      <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-6">{t('teacher_mgmt_title')}</h2>

      <form onSubmit={handleAdd} className="bg-white dark:bg-slate-800 p-8 rounded-[2.5rem] shadow-sm border border-slate-200 dark:border-slate-700 mb-8 transition-colors">
        <div className="flex flex-col gap-6">
            <div className="flex gap-4">
                <input 
                type="text" 
                value={newTeacherName}
                onChange={(e) => setNewTeacherName(e.target.value)}
                placeholder={t('teacher_name_placeholder')}
                className="flex-1 px-6 py-4 bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-2xl focus:ring-2 focus:ring-primary-500 outline-none dark:text-white transition-all font-bold"
                />
                <button 
                    type="submit"
                    disabled={!newTeacherName.trim()}
                    className="bg-primary-600 hover:bg-primary-700 text-white px-8 rounded-2xl flex items-center gap-2 disabled:opacity-50 transition-all whitespace-nowrap font-black shadow-lg shadow-primary-500/20"
                >
                    <Plus size={20} />
                    <span>{t('teacher_add_btn')}</span>
                </button>
            </div>

            <div className="flex items-center gap-4 bg-slate-50 dark:bg-slate-900/50 p-4 rounded-2xl transition-colors border dark:border-slate-700">
                <span className="text-sm font-black text-slate-600 dark:text-slate-400">{t('teacher_color_mode')}:</span>
                <div className="flex gap-2">
                    <button
                        type="button"
                        onClick={() => setColorMode('random')}
                        className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all border ${
                            colorMode === 'random' 
                            ? 'bg-white dark:bg-slate-800 border-primary-500 text-primary-600 dark:text-primary-400 shadow-md' 
                            : 'bg-transparent border-transparent text-slate-500 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-800'
                        }`}
                    >
                        <Shuffle size={16} />
                        <span>{t('teacher_color_random')}</span>
                    </button>
                    <button
                        type="button"
                        onClick={() => setColorMode('custom')}
                        className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all border ${
                            colorMode === 'custom' 
                            ? 'bg-white dark:bg-slate-800 border-primary-500 text-primary-600 dark:text-primary-400 shadow-md' 
                            : 'bg-transparent border-transparent text-slate-500 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-800'
                        }`}
                    >
                        <Palette size={16} />
                        <span>{t('teacher_color_custom')}</span>
                    </button>
                </div>
                {colorMode === 'custom' && (
                    <div className="flex items-center gap-2 animate-in slide-in-from-right-4 duration-300">
                        <input type="color" value={customColor} onChange={(e) => setCustomColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer border-2 border-white dark:border-slate-700 shadow-md" />
                    </div>
                )}
            </div>
        </div>
      </form>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {state.teachers.map(t_item => (
            <div key={t_item.id} className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 flex items-center justify-between group transition-all hover:shadow-md">
                {editingId === t_item.id ? (
                    <div className="flex items-center gap-2 w-full">
                        <input type="text" value={editName} onChange={(e) => setEditName(e.target.value)} className="flex-1 px-3 py-2 border dark:border-slate-600 rounded-xl bg-slate-50 dark:bg-slate-900 dark:text-white font-bold" autoFocus />
                        <button onClick={() => saveEdit(t_item)} className="text-green-600 p-2 bg-green-50 dark:bg-green-900/20 rounded-xl hover:bg-green-100"><Check size={20} /></button>
                    </div>
                ) : (
                    <>
                        <div className="flex items-center gap-4">
                            <div className="w-12 h-12 rounded-2xl flex items-center justify-center text-white font-black shadow-lg border-2 border-white dark:border-slate-700 text-xl" style={{ backgroundColor: t_item.color }}>
                                {t_item.name.charAt(0)}
                            </div>
                            <span className="font-black text-slate-800 dark:text-slate-200">{t_item.name}</span>
                        </div>
                        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button onClick={() => startEdit(t_item)} className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-xl"><Edit2 size={20} /></button>
                            <button onClick={() => setDeleteId(t_item.id)} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-xl"><Trash2 size={20} /></button>
                        </div>
                    </>
                )}
            </div>
        ))}
      </div>
      <ConfirmModal isOpen={!!deleteId} message="د دې ښوونکي په لرې کولو سره به د هغه ټول اړوند لوستونه له مهال ویش څخه لرې شي. ایا دوام ورکوئ؟" onCancel={() => setDeleteId(null)} onConfirm={confirmDelete} />
    </div>
  );
};

export default Teachers;
